const http = require('http');
const url = require('url');
const fs = require('fs');

const server = http.createServer((req, res) => {
  const parsed = url.parse(req.url, true);
  console.log('RECEIVED REQUEST:', req.url);

  if (parsed.pathname === '/callback') {
    const code = parsed.query.code;
    const state = parsed.query.state;
    const error = parsed.query.error;

    if (error) {
      console.log('ERROR:', error, parsed.query.error_description);
      fs.writeFileSync('/tmp/oidc_result.json', JSON.stringify({error}));
    } else if (code) {
      console.log('AUTH CODE:', code);
      console.log('STATE:', state);
      fs.writeFileSync('/tmp/oidc_result.json', JSON.stringify({code, state}));
    }

    res.writeHead(200, {'Content-Type': 'text/html'});
    res.end('<html><body><h1>Login successful! You can close this window.</h1></body></html>');
    server.close();
  } else {
    res.writeHead(404);
    res.end('Not found');
  }
});

