  // Store the original fetch to intercept it
  window._capturedRequests = [];
  const origFetch = window.fetch;
  window.fetch = async function(...args) {
    const url = typeof args[0] === 'string' ? args[0] : (args[0] && args[0].url);
    if (url && (url.includes('/delivery/') || url.includes('/api/qa'))) {
      // Clone request body if possible
      let body = null;
      if (args[1] && args[1].body) {
        body = args[1].body;
      }
      window._capturedRequests.push({url, body: String(body).substring(0, 2000), time: Date.now()});
    }
    return origFetch.apply(this, args);
  };
  return 'fetch interceptor installed';
}

