  // Setup network intercept before clicking
  const requests = [];

  // Intercept XHR/fetch via route
  await page.route('**/api/**', async (route) => {
    const request = route.request();
    const url = request.url();
    const method = request.method();
    let body = null;
    try {
      body = request.postData();
    } catch(e) {}

    requests.push({url, method, body: body ? body.substring(0, 2000) : null});
