  const formItems = createModal.querySelectorAll('.mtd-form-item');
  const results = [];

  formItems.forEach((item, i) => {
    const label = item.querySelector('.mtd-form-item-label');
    const inputs = item.querySelectorAll('input, textarea');
    const selects = item.querySelectorAll('.mtd-select, select');
    const hasRequired = item.querySelector('.required, [required]') !== null;
    const hasError = item.querySelector('.mtd-form-item-error, .is-error') !== null;

    results.push({
      index: i,
      label: label?.textContent?.trim(),
      inputs: Array.from(inputs).map(inp => ({ tag: inp.tagName, type: inp.type, value: inp.value, placeholder: inp.placeholder })),
      hasRequired,
      hasError,
      errorMsg: item.querySelector('.mtd-form-item-error-msg')?.textContent?.trim()
    });
  });

  return results;
}

