  const createModal = document.querySelector('.fsd-create-pipeline-modal');
  if (!createModal) return { error: 'no modal' };

  // 1. Fill 技术方案 textarea (form item 10)
  const formItems = createModal.querySelectorAll('.mtd-form-item');
  const techItem = formItems[10];
  const textarea = techItem?.querySelector('textarea');

  if (textarea) {
    const nativeTextareaValueSetter = Object.getOwnPropertyDescriptor(window.HTMLTextAreaElement.prototype, 'value').set;
    nativeTextareaValueSetter.call(textarea, '随单返首页弹窗一键开启功能，新增弹窗配置项，支持运营配置');
