    textarea.dispatchEvent(new Event('change', { bubbles: true }));
    textarea.dispatchEvent(new Event('blur', { bubbles: true }));
    console.log('技术方案 filled:', textarea.value);
  } else {
    console.log('textarea not found');
  }

  // 2. Check 测试人员 field
  const qaItem = formItems[5]; // index 5 is 测试人员
  const qaInputs = qaItem?.querySelectorAll('input');
  console.log('QA inputs count:', qaInputs?.length);

  return {
    textareaFilled: !!textarea,
    textareaValue: textarea?.value,
    qaInputsCount: qaInputs?.length,
    qaLabel: qaItem?.querySelector('.mtd-form-item-label')?.textContent?.trim()
  };
}

