() => {
  // Set up XHR/fetch interceptor to capture delivery creation response
  window._fsdDeliveryResponse = null;
  const origFetch = window.fetch;
  window.fetch = async function(...args) {
    const resp = await origFetch.apply(this, args);
    const url = typeof args[0] === 'string' ? args[0] : args[0]?.url;
    if (url && url.includes('/delivery/add')) {
      const clone = resp.clone();
      clone.json().then(data => {
        window._fsdDeliveryResponse = { url, data, status: resp.status };
        console.log('DELIVERY_RESPONSE:', JSON.stringify(data));
      }).catch(e => {
        window._fsdDeliveryResponse = { url, error: e.message, status: resp.status };
      });
    }
    return resp;
  };
  return 'interceptor installed';
}

