() => {
  // Install response interceptor first
  window._fsdDeliveryResponse = null;
  const origFetch = window.fetch;
  window.fetch = async function(...args) {
    const resp = await origFetch.apply(this, args);
    const url = typeof args[0] === 'string' ? args[0] : args[0]?.url;
    if (url && (url.includes('/delivery/add') || url.includes('/applyProgram') || url.includes('/delivery/create'))) {
      const clone = resp.clone();
      clone.text().then(text => {
        window._fsdDeliveryResponse = { url, text: text.substring(0, 2000), status: resp.status };
        console.log('DELIVERY_RESPONSE_URL:', url, 'STATUS:', resp.status);
        console.log('DELIVERY_RESPONSE_BODY:', text.substring(0, 1000));
      });
    }
    return resp;
  };

  // Also intercept XHR
  const origOpen = XMLHttpRequest.prototype.open;
  const origSend = XMLHttpRequest.prototype.send;
  XMLHttpRequest.prototype.open = function(method, url, ...args) {
    this._url = url;
    return origOpen.call(this, method, url, ...args);
  };
  XMLHttpRequest.prototype.send = function(body) {
    this.addEventListener('load', () => {
      if (this._url && (this._url.includes('/delivery/add') || this._url.includes('/applyProgram'))) {
        window._fsdDeliveryResponse = { url: this._url, text: this.responseText?.substring(0, 2000), status: this.status };
        console.log('XHR DELIVERY_RESPONSE:', this._url, this.status, this.responseText?.substring(0, 500));
      }
    });
    return origSend.call(this, body);
  };

  return 'interceptors installed';
}

